import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { archiveDoc, getDocs } from "../../api/documentApi";

export default function DocumentList() {
  const [docs, setDocs] = useState([]);
  const [loading, setLoading] = useState(false);

  const load = async () => {
    try {
      setLoading(true);
      const res = await getDocs();
      setDocs(res.data);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to load documents");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const archive = async (id) => {
    if (!window.confirm("Delete this document?")) return;
    try {
      await archiveDoc(id);
      setDocs((prev) => prev.filter((d) => d._id !== id));
      alert("Document archived");
    } catch (err) {
      alert(err.response?.data?.message || "Archive failed");
    }
  };

  return (
    <div style={{ padding: 20 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <h2 style={{ margin: 0 }}>Physical Documents</h2>
        <div style={{ display: "flex", gap: 10 }}>
          <button onClick={load} style={{ padding: "6px 10px" }}>Refresh</button>
          <Link to="/documents/add">
            <button style={{ padding: "6px 10px" }}>+ Add Document</button>
          </Link>
        </div>
      </div>

      <div style={{ marginTop: 14 }}>
        {loading && <p>Loading...</p>}

        {!loading && (
          <table border="1" cellPadding="10" style={{ width: "100%", textAlign: "left" }}>
            <thead>
              <tr>
                <th>Title</th>
                <th>Type</th>
                <th>Vehicle</th>
                <th>Status</th>
                <th>Location</th>
                <th>Holder</th>
                <th style={{ width: 180 }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {docs.map((d) => (
                <tr key={d._id}>
                  <td>{d.title}</td>
                  <td>{d.docType}</td>
                  <td>
                    {d.vehicle ? `${d.vehicle.brand} ${d.vehicle.model || ""}` : "-"}
                  </td>
                  <td>{d.status}</td>
                  <td>{d.location}</td>
                  <td>{d.holder?.name || d.holder?.email || "-"}</td>
                  <td>
                    <Link to={`/documents/edit/${d._id}`}>
                      <button>Edit</button>
                    </Link>
                    <button onClick={() => archive(d._id)} style={{ marginLeft: 6 }}>
                      Delete
                    </button>
                  </td>
                </tr>
              ))}

              {docs.length === 0 && (
                <tr>
                  <td colSpan="7">No documents found</td>
                </tr>
              )}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
